import subprocess
import sys
import os
import argparse

def create_backup(source_dir, format_type, output_name):
    allowed_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    allowed_commands = {
        'tar.gz': ['tar', '-czf'],
        'tar.bz2': ['tar', '-cjf'],
        'zip': ['zip', '-r'],
        '7z': ['7z', 'a']
    }
    
    if format_type not in allowed_formats:
        raise ValueError(f"Unsupported format. Choose from {allowed_formats}")
    
    if not os.path.exists(source_dir):
        raise FileNotFoundError(f"Source directory {source_dir} does not exist")
    
    command = allowed_commands[format_type]
    
    if format_type == '7z':
        archive_name = f"{output_name}.7z"
        command.extend([archive_name, source_dir])
    elif format_type == 'zip':
        archive_name = f"{output_name}.zip"
        command.extend([archive_name, source_dir])
    else:
        archive_name = f"{output_name}.{format_type}"
        command.extend([archive_name, source_dir])
    
    try:
        result = subprocess.run(command, check=True, shell=False, 
                              stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        print(f"Backup created successfully: {archive_name}")
        return archive_name
    except subprocess.CalledProcessError as e:
        print(f"Error creating backup: {e.stderr.decode()}")
        sys.exit(1)
    except FileNotFoundError:
        print("Required compression tool not found")
        sys.exit(1)

def main():
    parser = argparse.ArgumentParser(description='Create compressed backup of user directories')
    parser.add_argument('source_dir', help='Directory to backup')
    parser.add_argument('format', choices=['tar.gz', 'tar.bz2', 'zip', '7z'], 
                       help='Compression format')
    parser.add_argument('output_name', help='Output archive name (without extension)')
    
    args = parser.parse_args()
    
    create_backup(args.source_dir, args.format, args.output_name)

if __name__ == "__main__":
    main()